\documentclass[11pt]{article}
\usepackage{amsmath,amssymb,amsthm}
\usepackage[margin=1.2in]{geometry}
\usepackage{microtype}
\usepackage{parskip}

\begin{document}
\pagestyle{empty}

\begin{center}
  {\large\bfseries RetroDiff: Training Objective Derivation}
\end{center}

\medskip

\noindent
Let $x$ denote a clean data sample and $x_t$ its noised counterpart at diffusion step $t \in \{1,\ldots,T\}$.
The forward process $q(x_{1:T}|x)$ gradually corrupts $x$; the model $p_\theta$ learns to reverse it.
Applying Jensen's inequality to the log-likelihood yields the \emph{evidence lower bound} (ELBO):

\begin{align}
  \log p_\theta(x) \;\geq\;
  \mathbb{E}_{q(x_{1:T}|x)}\!\left[\log\frac{p_\theta(x_{0:T})}{q(x_{1:T}|x)}\right]
  = -\mathcal{L}_{\mathrm{ELBO}}
  \label{eq:elbo}
\end{align}

\noindent
The bound in \eqref{eq:elbo} is tight when $q = p_\theta$.
Expanding the joint by the Markov structure of the diffusion chain and applying Bayes' theorem
to each reverse step decomposes $\mathcal{L}_{\mathrm{ELBO}}$ into a reconstruction term and
a sum of per-step KL divergences:

\begin{align}
  \mathcal{L}_{\mathrm{ELBO}}
  &= \underbrace{\mathbb{E}_q\!\left[-\log p_\theta(x_0|x_1)\right]}_{\text{reconstruction}}
  + \sum_{t=2}^{T}
    \underbrace{\mathrm{KL}\!\left(q(x_{t-1}|x_t,x)\,\|\,p_\theta(x_{t-1}|x_t)\right)}_{\text{step-}t\text{ denoising}}
  \label{eq:decomp}
\end{align}

\noindent
Each KL term in \eqref{eq:decomp} is tractable because the forward posterior
$q(x_{t-1}|x_t,x)$ is Gaussian.
\textbf{RetroDiff}'s key contribution is to condition the entire objective on a set
$R(x)$ of $k$ exemplars retrieved from the training corpus based on $x$.
Averaging over the data distribution gives the final training objective:

\begin{align}
  \mathcal{L}_{\mathrm{RetroDiff}}(\theta)
  = \mathbb{E}_{x \sim p_{\mathrm{data}}}\!\left[
      \mathcal{L}_{\mathrm{ELBO}}\!\left(x \,\big|\, R(x)\right)
    \right]
  \label{eq:retro}
\end{align}

\noindent
Equation~\eqref{eq:retro} reduces to the standard DDPM objective when $R(x) = \varnothing$,
making RetroDiff a strict generalisation of the baseline diffusion framework.

\end{document}

